{
  "query": "mutation Register($input: CreateUserInput!) { register(createUserInput: $input) { _id email username firstName lastName roles isActive createdAt } }",
  "variables": {
    "input": {
      "email": "alice@example.com",
      "username": "alice",
      "password": "Secret123!",
      "firstName": "Alice",
      "lastName": "Smith"
    }
  }
}

{
  "query": "mutation Login($input: LoginInput!) { login(loginInput: $input) { accessToken user { _id email username roles } } }",
  "variables": {
    "input": {
      "emailOrUsername": "alice@example.com",
      "password": "Secret123!"
    }
  }
}

{
  "query": "query Me { me { _id email username firstName lastName bio avatar roles isActive createdAt updatedAt } }"
}

{
  "query": "query Users { users { _id email username firstName lastName roles isActive createdAt } }"
}

{
  "query": "query User($id: ID!) { user(id: $id) { _id email username firstName lastName bio avatar roles isActive createdAt updatedAt } }",
  "variables": {
    "id": "{{user_id}}"
  }
}

{
  "query": "mutation UpdateProfile($input: UpdateUserInput!) { updateProfile(updateUserInput: $input) { _id firstName lastName bio avatar updatedAt } }",
  "variables": {
    "input": {
      "firstName": "Alicia",
      "lastName": "Smith",
      "bio": "Software developer",
      "avatar": "https://example.com/avatar.png"
    }
  }
}
